from typing import List
import math

class Solution:
    def maxScore(self, nums: List[int]) -> int:
        n = len(nums) // 2
        memo = {}

        def backtrack(mask, i):
            if mask in memo:
                return memo[mask]
            if i > n:
                return 0

            max_score = 0
            for j in range(len(nums)):
                if (mask & (1 << j)) == 0:
                    for k in range(j + 1, len(nums)):
                        if (mask & (1 << k)) == 0:
                            new_mask = mask | (1 << j) | (1 << k)
                            score = i * math.gcd(nums[j], nums[k]) + backtrack(new_mask, i + 1)
                            max_score = max(max_score, score)
            memo[mask] = max_score
            return max_score

        return backtrack(0, 1)

